/**
 * icon-browser-demo
 *
 * Standalone, self-contained custom element for the UWC Components docs.
 * Fetches Iconify JSON bundles (one request per provider) so the entire icon
 * set is available client-side with NO per-icon HTTP requests.
 *
 * NOT exported from src/index.ts or src/react.bundle.ts —
 * built to _site/js/icon-browser.js via a dedicated esbuild entry.
 *
 * Bundle URLs (Iconify JSON format via jsDelivr CDN)
 * ──────────────────────────────────────────────────
 * Bootstrap Icons  →  @iconify-json/bi/icons.json       (~300 KB)
 * Material Icons   →  @iconify-json/mdi/icons.json      (~1.7 MB)
 * Font Awesome     →  @iconify-json/fa-{solid,regular,brands}/icons.json
 */

import { LitElement, html, css, nothing, type TemplateResult } from 'lit';
import { customElement, state } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { unsafeSVG } from 'lit/directives/unsafe-svg.js';

// ── Types ─────────────────────────────────────────────────────────────────────

type Provider = 'bootstrap' | 'mdi' | 'fontawesome';
type Variant  = 'all' | 'outlined' | 'filled';

interface IconEntry {
  /** Icon name as used in the <uwc-icon> tag. */
  name:   string;
  /** Full `<svg xmlns="…" viewBox="…">…</svg>` string ready for unsafeSVG. */
  svg:    string;
  /** Font Awesome style bucket. Absent for Bootstrap / MDI. */
  style?: 'solid' | 'regular' | 'brands';
}

// ── Iconify JSON bundle types ─────────────────────────────────────────────────

interface IjIconData {
  body: string;
  width?:  number;
  height?: number;
}
interface IjBundle {
  prefix:   string;
  icons:    Record<string, IjIconData>;
  aliases?: Record<string, { parent: string }>;
  width?:   number;
  height?:  number;
}

// ── CDN URLs for Iconify JSON bundles ─────────────────────────────────────────

const CDN = 'https://cdn.jsdelivr.net/npm/@iconify-json';
const BUNDLE_URLS = {
  bootstrap:            `${CDN}/bi/icons.json`,
  mdi:                  `${CDN}/mdi/icons.json`,
  'fa-solid':           `${CDN}/fa-solid/icons.json`,
  'fa-regular':         `${CDN}/fa-regular/icons.json`,
  'fa-brands':          `${CDN}/fa-brands/icons.json`,
} as const;

// ── Provider tab metadata ─────────────────────────────────────────────────────

const PROVIDERS: Array<{ id: Provider; label: string }> = [
  { id: 'bootstrap',   label: 'Bootstrap'      },
  { id: 'mdi',         label: 'Material Icons' },
  { id: 'fontawesome', label: 'Font Awesome'   },
];

// ── Iconify JSON → IconEntry[] parser ─────────────────────────────────────────

function _wrapSvg(body: string, w: number, h: number): string {
  // viewBox only — no width/height attributes so CSS sizing wins unconditionally
  // (Bootstrap Icons emit viewBox="0 0 16 16"; MDI/FA emit "0 0 24 24").
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}">${body}</svg>`;
}

function _parseBundle(
  data: IjBundle,
  style?: IconEntry['style'],
): IconEntry[] {
  const dw = data.width  ?? 24;
  const dh = data.height ?? 24;
  const map = new Map<string, string>();

  for (const [name, icon] of Object.entries(data.icons)) {
    map.set(name, _wrapSvg(icon.body, icon.width ?? dw, icon.height ?? dh));
  }
  // Resolve aliases — give them the parent's SVG string
  if (data.aliases) {
    for (const [alias, meta] of Object.entries(data.aliases)) {
      const parent = map.get(meta.parent);
      if (parent) map.set(alias, parent);
    }
  }

  const result: IconEntry[] = [];
  for (const [name, svg] of map) {
    result.push({ name, svg, style });
  }
  return result;
}

// ── Copied tag generator ───────────────────────────────────────────────────────

function _iconTag(provider: Provider, icon: IconEntry): string {
  if (provider === 'bootstrap') {
    return `<uwc-icon name="${icon.name}"></uwc-icon>`;
  }
  if (provider === 'mdi') {
    return `<uwc-icon name="${icon.name}" library="mdi"></uwc-icon>`;
  }
  return `<uwc-icon name="${icon.name}" library="fontawesome-${icon.style}"></uwc-icon>`;
}

// ── icon-browser-demo ─────────────────────────────────────────────────────────

@customElement('icon-browser-demo')
export class IconBrowserDemo extends LitElement {
  static override styles = css`
    :host {
      display: block;
      font-size: .875rem;
      font-family: inherit;
      position: relative; /* anchor for the JS-positioned tooltip */
    }

    /* ── Provider tabs ──────────────────────────────────────────────────── */
    .tabs {
      display: flex;
      border-bottom: 1px solid #e2e8f0;
      margin-bottom: 1rem;
    }
    .tab {
      padding: .5rem 1.125rem;
      border: none;
      background: none;
      cursor: pointer;
      font-size: .875rem;
      color: #64748b;
      border-bottom: 2px solid transparent;
      margin-bottom: -1px;
      font-family: inherit;
      line-height: 1.5;
      white-space: nowrap;
      transition: color 120ms, border-color 120ms;
    }
    .tab:hover { color: #1e293b; }
    .tab.active {
      color: #6366f1;
      border-bottom-color: #6366f1;
      font-weight: 600;
    }

    /* ── Toolbar ────────────────────────────────────────────────────────── */
    .toolbar {
      display: flex;
      gap: .75rem;
      margin-bottom: .5rem;
      align-items: center;
    }
    .sw {
      flex: 1;
      position: relative;
      display: flex;
      align-items: center;
    }
    .si {
      position: absolute;
      left: .75rem;
      color: #94a3b8;
      pointer-events: none;
      display: flex;
      align-items: center;
    }
    input[type=search] {
      width: 100%;
      box-sizing: border-box;
      padding: .5rem .75rem .5rem 2.25rem;
      border: 1px solid #e2e8f0;
      border-radius: 6px;
      font-size: .875rem;
      outline: none;
      transition: border-color 120ms;
      font-family: inherit;
      background: #fff;
      -webkit-appearance: none;
    }
    input[type=search]:focus { border-color: #6366f1; }
    select {
      padding: .5rem .625rem;
      border: 1px solid #e2e8f0;
      border-radius: 6px;
      font-size: .875rem;
      background: #fff;
      cursor: pointer;
      min-width: 130px;
      font-family: inherit;
      outline: none;
      line-height: 1.4;
    }
    select:focus { border-color: #6366f1; }

    /* ── Icon count ─────────────────────────────────────────────────────── */
    .count { font-size: .75rem; color: #94a3b8; margin: 0 0 .5rem; }

    /* ── Scrollable grid container ──────────────────────────────────────── */
    .wrap {
      max-height: 60vh;
      overflow-y: auto;
      border: 1px solid #e2e8f0;
      border-radius: 8px;
      padding: 1rem;
      scrollbar-width: thin;
      scrollbar-color: #cbd5e1 transparent;
    }
    .wrap::-webkit-scrollbar       { width: 6px; }
    .wrap::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 9999px; }

    /* ── Grid ────────────────────────────────────────────────────────────── */
    .grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(52px, 1fr));
      gap: .25rem;
    }

    /* ── Icon cell — fixed 48×48 square, icon centred inside ────────────── */
    .ic {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 48px;
      height: 48px;
      border-radius: 6px;
      cursor: pointer;
      transition: background 120ms;
      border: none;
      background: none;
      font-family: inherit;
      color: #374151;
      padding: 0;
      box-sizing: border-box;
    }
    .ic:hover { background: #f1f5f9; }

    /* .ic-svg is a plain 24×24 flex wrapper. !important on the SVG dimensions
       overrides any presentation attributes (e.g. Bootstrap Icons width="16")
       regardless of shadow DOM specificity context. */
    .ic-svg {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 24px;
      height: 24px;
      flex-shrink: 0;
      line-height: 0;
      font-size: 0;
    }
    .ic-svg svg {
      display: block;
      width: 24px !important;
      height: 24px !important;
      fill: currentColor;
      overflow: visible;
    }

    /* ── Loading / empty / error states ─────────────────────────────────── */
    .state {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 200px;
      gap: .625rem;
      color: #94a3b8;
      font-size: .875rem;
      text-align: center;
    }
    .state.err { color: #ef4444; }

    /* Spinner ring for loading state (CSS-only, no uwc-icon dependency) */
    .spinner-ring {
      width: 28px;
      height: 28px;
      border: 3px solid #e2e8f0;
      border-top-color: #6366f1;
      border-radius: 50%;
      animation: spin 0.8s linear infinite;
    }
    @keyframes spin { to { transform: rotate(360deg); } }

    /* ── Floating tooltip ─────────────────────────────────────────────────
       Sibling to .wrap — never clipped by the overflow-y container.
       Positioned via JS (getBoundingClientRect) relative to :host.
    ──────────────────────────────────────────────────────────────────────── */
    .tooltip {
      position: absolute;
      z-index: 100;
      background: #1e293b;
      color: #f8fafc;
      border-radius: 6px;
      padding: .5rem .75rem;
      font-size: .75rem;
      pointer-events: none;
      transform: translateX(-50%) translateY(calc(-100% - 10px));
      display: flex;
      flex-direction: column;
      gap: .2rem;
      max-width: 300px;
      box-shadow: 0 4px 16px rgba(0,0,0,.25);
      white-space: nowrap;
    }
    .tooltip::after {
      content: '';
      position: absolute;
      top: 100%;
      left: 50%;
      transform: translateX(-50%);
      border: 5px solid transparent;
      border-top-color: #1e293b;
    }
    .tip-name  { font-weight: 600; font-size: .8125rem; }
    .tip-variant { font-size: .6875rem; color: #a5b4fc; text-transform: capitalize; }
    .tip-tag   {
      font-size: .6875rem;
      color: #94a3b8;
      font-family: ui-monospace, 'Cascadia Code', 'Fira Code', monospace;
      overflow: hidden;
      text-overflow: ellipsis;
      max-width: 280px;
    }
    .tip-action         { font-size: .6875rem; color: #64748b; }
    .tip-action.copied  { color: #4ade80; }

    @media (prefers-reduced-motion: reduce) {
      .tab, input[type=search], select, .ic, .spinner-ring { transition: none; animation: none; }
    }
  `;

  // ── Internal state ──────────────────────────────────────────────────────────

  @state() private _provider: Provider = 'bootstrap';
  @state() private _search   = '';
  @state() private _variant: Variant = 'all';
  @state() private _icons: IconEntry[] = [];
  @state() private _loading  = false;
  @state() private _err      = '';
  @state() private _tip: { icon: IconEntry; x: number; y: number } | null = null;
  @state() private _copied   = false;

  /** Per-provider cache — avoids re-fetching when switching tabs. */
  private readonly _cache = new Map<Provider, IconEntry[]>();
  private _copyTimer?: ReturnType<typeof setTimeout>;

  // ── Lifecycle ───────────────────────────────────────────────────────────────

  override async connectedCallback() {
    super.connectedCallback();
    await this._load('bootstrap');
  }

  override disconnectedCallback() {
    super.disconnectedCallback();
    clearTimeout(this._copyTimer);
  }

  // ── Data loading ────────────────────────────────────────────────────────────

  private async _load(provider: Provider) {
    if (this._cache.has(provider)) {
      this._icons = this._cache.get(provider)!;
      return;
    }
    this._loading = true;
    this._err = '';
    try {
      const icons = await this._fetchProvider(provider);
      this._cache.set(provider, icons);
      this._icons = icons;
    } catch {
      this._err = `Failed to load ${PROVIDERS.find(p => p.id === provider)?.label} icons. Check your network.`;
    } finally {
      this._loading = false;
    }
  }

  private async _fetchBundle(url: string): Promise<IjBundle> {
    const r = await fetch(url);
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    return r.json();
  }

  private async _fetchProvider(provider: Provider): Promise<IconEntry[]> {
    switch (provider) {

      case 'bootstrap': {
        const data = await this._fetchBundle(BUNDLE_URLS.bootstrap);
        return _parseBundle(data).sort((a, b) => a.name.localeCompare(b.name));
      }

      case 'mdi': {
        const data = await this._fetchBundle(BUNDLE_URLS.mdi);
        return _parseBundle(data).sort((a, b) => a.name.localeCompare(b.name));
      }

      case 'fontawesome': {
        const [solid, regular, brands] = await Promise.all([
          this._fetchBundle(BUNDLE_URLS['fa-solid']),
          this._fetchBundle(BUNDLE_URLS['fa-regular']),
          this._fetchBundle(BUNDLE_URLS['fa-brands']),
        ]);
        const icons: IconEntry[] = [
          ..._parseBundle(solid,   'solid'),
          ..._parseBundle(regular, 'regular'),
          ..._parseBundle(brands,  'brands'),
        ];
        return icons.sort((a, b) =>
          a.name.localeCompare(b.name) || (a.style ?? '').localeCompare(b.style ?? '')
        );
      }
    }
  }

  // ── Filtering ───────────────────────────────────────────────────────────────

  private get _filtered(): IconEntry[] {
    const q = this._search.toLowerCase().trim();

    return this._icons.filter(icon => {
      // Search filter
      if (q && !icon.name.includes(q)) return false;

      // Variant filter
      if (this._variant !== 'all') {
        switch (this._provider) {
          case 'bootstrap':
            if (this._variant === 'filled')   return icon.name.endsWith('-fill');
            if (this._variant === 'outlined') return !icon.name.endsWith('-fill');
            break;
          case 'mdi':
            if (this._variant === 'filled')   return !icon.name.endsWith('-outline');
            if (this._variant === 'outlined') return icon.name.endsWith('-outline');
            break;
          case 'fontawesome':
            if (this._variant === 'filled')   return icon.style === 'solid';
            if (this._variant === 'outlined') return icon.style === 'regular';
            break;
        }
      }
      return true;
    });
  }

  // ── Interactions ────────────────────────────────────────────────────────────

  private _setProvider(p: Provider) {
    if (p === this._provider) return;
    this._provider = p;
    this._search   = '';
    this._variant  = 'all';
    this._tip      = null;
    this._icons    = this._cache.get(p) ?? [];
    this._load(p);
  }

  private _onEnter(e: MouseEvent, icon: IconEntry) {
    const elRect   = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const hostRect = this.getBoundingClientRect();
    this._tip = {
      icon,
      x: elRect.left - hostRect.left + elRect.width  / 2,
      y: elRect.top  - hostRect.top,
    };
  }

  private _onLeave() { this._tip = null; }

  private async _copy(icon: IconEntry) {
    const tag = _iconTag(this._provider, icon);
    try {
      await navigator.clipboard.writeText(tag);
    } catch {
      const ta = document.createElement('textarea');
      ta.value = tag;
      ta.style.cssText = 'position:fixed;opacity:0';
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      ta.remove();
    }
    this._copied = true;
    clearTimeout(this._copyTimer);
    this._copyTimer = setTimeout(() => { this._copied = false; }, 1800);
  }

  // ── Render helpers ──────────────────────────────────────────────────────────

  private _variantOptions(): TemplateResult {
    if (this._provider === 'fontawesome') {
      return html`
        <option value="all">All styles</option>
        <option value="filled">Solid</option>
        <option value="outlined">Regular</option>
      `;
    }
    return html`
      <option value="all">All icons</option>
      <option value="outlined">Outlined</option>
      <option value="filled">Filled</option>
    `;
  }

  // ── Render ──────────────────────────────────────────────────────────────────

  protected override render() {
    const filtered = this._filtered;

    return html`
      <!-- ── Provider tabs ────────────────────────────────────────────── -->
      <div class="tabs" role="tablist">
        ${PROVIDERS.map(({ id, label }) => html`
          <button
            class=${classMap({ tab: true, active: this._provider === id })}
            role="tab"
            aria-selected=${this._provider === id ? 'true' : 'false'}
            @click=${() => this._setProvider(id)}
          >${label}</button>
        `)}
      </div>

      <!-- ── Toolbar ──────────────────────────────────────────────────── -->
      <div class="toolbar">
        <div class="sw">
          <span class="si">
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
              <path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0 0 16 9.5 6.5 6.5 0 1 0 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/>
            </svg>
          </span>
          <input
            type="search"
            placeholder="Search icons…"
            .value=${this._search}
            @input=${(e: InputEvent) => {
              this._search = (e.target as HTMLInputElement).value;
              this._tip = null;
            }}
          />
        </div>
        <select
          @change=${(e: Event) => {
            this._variant = (e.target as HTMLSelectElement).value as Variant;
            this._tip = null;
          }}
        >${this._variantOptions()}</select>
      </div>

      <!-- ── Count ────────────────────────────────────────────────────── -->
      ${!this._loading ? html`
        <p class="count">
          ${filtered.length.toLocaleString()} icon${filtered.length !== 1 ? 's' : ''}
        </p>
      ` : nothing}

      <!-- ── Icon grid ────────────────────────────────────────────────── -->
      <div class="wrap" @scroll=${() => { this._tip = null; }}>
        ${this._loading ? html`
          <div class="state">
            <div class="spinner-ring" role="status" aria-label="Loading icons"></div>
            <span>Loading icons…</span>
          </div>
        ` : this._err ? html`
          <div class="state err">${this._err}</div>
        ` : filtered.length === 0 ? html`
          <div class="state">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="currentColor">
              <path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0 0 16 9.5 6.5 6.5 0 1 0 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/>
            </svg>
            <span>No icons match &ldquo;${this._search}&rdquo;</span>
          </div>
        ` : html`
          <div class="grid">
            ${filtered.map(icon => html`
              <button
                class="ic"
                tabindex="-1"
                @mouseenter=${(e: MouseEvent) => this._onEnter(e, icon)}
                @mouseleave=${this._onLeave}
                @click=${() => this._copy(icon)}
              >
                <span class="ic-svg">${unsafeSVG(icon.svg)}</span>
              </button>
            `)}
          </div>
        `}
      </div>

      <!-- ── Floating tooltip (outside .wrap — never clipped by overflow) ─ -->
      ${this._tip ? html`
        <div
          class="tooltip"
          style="left:${this._tip.x}px;top:${this._tip.y}px"
          aria-hidden="true"
        >
          <span class="tip-name">
            ${this._tip.icon.name}${this._tip.icon.style
              ? html` <span class="tip-variant">(${this._tip.icon.style})</span>`
              : nothing}
          </span>
          <span class="tip-tag">${_iconTag(this._provider, this._tip.icon)}</span>
          <span class=${classMap({ 'tip-action': true, copied: this._copied })}>
            ${this._copied ? '✓ Copied!' : 'Click to copy tag'}
          </span>
        </div>
      ` : nothing}
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'icon-browser-demo': IconBrowserDemo;
  }
}
